-- Fase 15: correcciones de nombre/descripcion y grupos musculares finales,
-- cargadas por el usuario en Catalogo_ejercicios_Apex_v2.xlsx. Matchea por
-- "code" (estable), no por nombre, asi que no importa que el nombre cambie.
-- CD0041 y CD0064 quedaron con el mismo nombre corregido ("Push up") en la
-- planilla; por acuerdo explicito quedan: CD0041 = "Push up" (flexiones de
-- piso), CD0064 = "Press de pecho con mancuernas" (antes "Press de Pecho -
-- Fuerza"). Grupos musculares normalizados (mayusculas/plural) y "escalada"
-- mapeado a "Escalada general" (grupo nuevo agregado a la taxonomia).
--
-- Correr en el SQL Editor de Supabase.

update exercises set name = '1 on / 1 off', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Intervalos de intensidad media estructurados con proporción trabajo-descanso 1:1. Escala durante 1 minuto, descansa 1 minuto, y repite durante varias series. Objetivo: Estresar tu sistema de capacidad aeróbica con intervalos que se vuelven progresivamente más difíciles de recuperar hacia el final del entrenamiento. Descanso: 60 s entre series' where code = 'AB0001';
update exercises set name = '1 on / 2 off', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Intervalos de intensidad media estructurados con proporción trabajo-descanso 1:2. Escala durante 1 minuto, descansa 2 minutos, y repite durante varias series. Objetivo: Estresar tu sistema de capacidad aeróbica con intervalos que permiten mayor recuperación, construyendo una base sólida de resistencia. Descanso: 2 min entre series' where code = 'AB0002';
update exercises set name = '10 on / 10 off', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Escala de forma continua durante 10 minutos a intensidad muy baja, seguido de descanso, repetido durante varias series en rutas o circuitos. Objetivo: Promover la recuperación y el flujo sanguíneo mediante volumen de escalada de baja intensidad, reconstruyendo la base de resistencia sin agregar estrés significativo de entrenamiento. Descanso: 10 min entre series' where code = 'AB0003';
update exercises set name = '5 on / 3 off', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Escala de forma continua durante 5 minutos a intensidad muy baja, seguido de descanso, repetido durante varias series en rutas o circuitos. Objetivo: Promover la recuperación mediante intervalos de escalada suave, aumentando el flujo sanguíneo para ayudar a la reparación de tejidos mientras se construye la base de resistencia. Descanso: 3 min entre series' where code = 'AB0004';
update exercises set name = '15+15 - facil a moderado', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Alterna entre 15 movimientos fáciles y 15 movimientos moderados en cada repetición, practicando la habilidad de cambiar de intensidad a mitad de la escalada. Objetivo: Desarrollar la capacidad aeróbica mientras se aprende a adaptar el ritmo y el estilo de escalada entre secciones de distinta intensidad. Descanso: 10 min entre series' where code = 'AB0005';
update exercises set name = '15+15 - moderado a facil', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Comienza cada repetición en una ruta moderada durante 15 movimientos, luego cambia a escalada más fácil durante los 15 movimientos restantes. Objetivo: Desarrollar la capacidad aeróbica mientras se aprende a manejar el bombeo y a transicionar entre intensidades de escalada. Descanso: 10 min entre series' where code = 'AB0006';
update exercises set name = '8 on / 5 off', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Escala de forma continua durante 8 minutos a intensidad muy baja, seguido de descanso, repetido durante varias series en rutas o circuitos. Objetivo: Apoyar la recuperación y la base de resistencia mediante intervalos de escalada de baja intensidad y duración moderada, aumentando el flujo sanguíneo sin sobrecargar el sistema. Descanso: 5 min entre series' where code = 'AB0007';
update exercises set name = 'ARC bajo', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Escala de forma continua durante 10 minutos a intensidad muy baja, manteniendo un movimiento fácil en rutas o circuitos sin acercarte al fallo. Objetivo: Promover la recuperación activa y construir una base aeróbica mediante un periodo sostenido de escalada fácil, apoyando el desarrollo de resistencia a largo plazo.' where code = 'AB0008';
