update exercises set name = 'ARC medio', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Escala de forma continua durante 20 minutos a intensidad muy baja, manteniendo un movimiento fácil en rutas o circuitos sin acercarte al fallo. Objetivo: Apoyar la recuperación activa y la construcción de la base aeróbica mediante un bloque de duración media de escalada fácil.' where code = 'AB0010';
update exercises set name = 'Boulder Volumen', muscle_groups = '["Dedos","Escalada general"]'::jsonb, description = 'Escala 10-20 boulders muy fáciles a baja intensidad, priorizando el ritmo y el movimiento fluido en todo momento. Objetivo: Desarrollar la capacidad aeróbica y la capilarización del antebrazo mediante boulder de alto volumen y muy baja intensidad.' where code = 'AB0011';
